//PackageAT004definesanAnalyzerthatchecksfor//TestStepConfigcontainingproviderconfigurationpackageAT004import(	"go/ast"	"go/token"	"strings"	"github.com/bflad/tfproviderlint/passes/commentignore"	"golang.org/x/tools/go/analysis"	"golang.org/x/tools/go/analysis/passes/inspect"	"golang.org/x/tools/go/ast/inspector")constDoc=`checkforTestStepConfigcontainingproviderconfigurationTheAT004analyzerreportslikelyincorrectusesofTestStepConfigwhichdefineaproviderconfiguration.Providerconfigurationsshouldbehandledoutsideindividualtestconfigurations(e.g.environmentvariables).`constanalyzerName="AT004"varAnalyzer=&analysis.Analyzer{	Name:analyzerName,	Doc:Doc,	Requires:[]*analysis.Analyzer{		commentignore.Analyzer,		inspect.Analyzer,	},	Run:run,}run(pass*analysis.Pass)(interface{},error){	ignorer:=pass.ResultOf[commentignore.Analyzer].(*commentignore.Ignorer)	inspect:=pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)	nodeFilter:=[]ast.Node{		(*ast.BasicLit)(nil),	}	inspect.Preorder(nodeFilter,(nast.Node){		x:=n.(*ast.BasicLit)		ifignorer.ShouldIgnore(analyzerName,x){			return		}		ifx.Kind!=token.STRING{			return		}		if!strings.Contains(x.Value,`provider"`){			return		}		pass.Reportf(x.ValuePos,"%s:providerdeclarationshouldbeomitted",analyzerName)	})	returnnil,nil}